"""Main screen — single screen, popup connect dialog."""

import logging
from pathlib import Path

from textual.app import ComposeResult
from textual.containers import Horizontal, Vertical
from textual.screen import Screen
from textual.widgets import Label, Static

from termzilla.components.file_table import FileTable
from termzilla.components.status_bar import StatusBar
from termzilla.screens.connect_dialog import ConnectDialog
from termzilla.services.connection_manager import ConnectionManager, ConnectionError
from termzilla.services.file_operations import LocalFileSystem, RemoteFileSystem
from termzilla.services.transfer_engine import TransferEngine
from termzilla.utils.validators import (
    validate_host, validate_port, validate_username, validate_ssh_key_path,
)

logger = logging.getLogger("termzilla")


class MainScreen(Screen):
    """Single-screen dual-pane file browser with inline connect."""

    BANNER = (
        "[bold green]"
        " ___   ___  ___    ___  ___      ___  ___  ___ \n"
        "/   | /  \\ |  \\  /  / |  \\     |  / |  / |  / \n"
        "|    |    |   \\/  /  |   \\    |  /  |  /  |  /  \n"
        "| __ | || | |\\  /   | |\\ \\   |  /   |  /   |  /  \n"
        "|  | | || | | \\/    | | \\ |  |  \\   |  \\   |  \\  \n"
        "|__|  \\__/  |_|     |_|  \\_| |___\\ |___\\ |___\\ \n"
        "[/]"
    )

    BINDINGS = [
        ("ctrl+c",       "quit",        "Quit"),
        ("f5",           "upload",      "Upload"),
        ("f6",           "download",    "Download"),
        ("f3",           "copy_file",   "Copy"),
        ("f4",           "move_file",   "Move"),
        ("f7",           "new_dir",     "New Dir"),
        ("f8",           "connect",     "Connect"),
        ("tab",          "switch_pane", "Switch"),
    ]

    def compose(self) -> ComposeResult:
        yield Static(self.BANNER, id="banner")
        with Horizontal(id="browser-layout"):
            with Vertical(id="local-pane"):
                yield Label("  Local", id="local-title")
                yield FileTable(id="local-table")
            with Vertical(id="remote-pane"):
                yield Label("  Remote", id="remote-title")
                yield Static("  [dim]Press F8 to connect to a remote server[/]", id="remote-placeholder")
                yield FileTable(id="remote-table")
        yield StatusBar(id="status-bar")

    def on_mount(self) -> None:
        self._prompt_mode = None       # None | "copy" | "move" | "new_dir"
        self._prompt_buffer = ""
        self._prompt_source_path = None
        self._message = ""
        self._connected = False

        # Connection manager
        self.connection_manager = ConnectionManager()
        self.local_fs = LocalFileSystem()
        self.remote_fs = None
        self.transfer_engine = None

        self.local_table = self.query_one("#local-table", FileTable)
        self.remote_table = self.query_one("#remote-table", FileTable)
        self.placeholder   = self.query_one("#remote-placeholder", Static)
        self.status_bar    = self.query_one("#status-bar", StatusBar)

        self._refresh_local()
        self.remote_table.display = False
        self._refresh_status_bar()
        self.local_table.focus()
        self._focused_pane = "local"

    # ── Prompt helpers ────────────────────────────────────────────────

    def _enter_prompt(self, mode: str, source_path: str = "") -> None:
        self._prompt_mode = mode
        self._prompt_buffer = ""
        self._prompt_source_path = source_path
        self._message = ""
        self._refresh_status_bar()

    def _exit_prompt(self) -> None:
        self._prompt_mode = None
        self._prompt_buffer = ""
        self._prompt_source_path = None
        self._message = ""
        self._refresh_status_bar()

    # ── Status bar ────────────────────────────────────────────────────

    def _refresh_status_bar(self) -> None:
        if self._prompt_mode in ("copy", "move", "new_dir"):
            mode_labels = {"copy": "Copy to:", "move": "Move to:", "new_dir": "New dir:"}
            label = mode_labels[self._prompt_mode]
            src_info = ""
            if self._prompt_source_path:
                src_info = f" ({Path(self._prompt_source_path).name})"
            self.status_bar.override_text = (
                f" [bold]{label}[/] {self._prompt_buffer}{src_info}"
                f"  [dim]Enter=ok  Esc=cancel[/]"
            )
            self.status_bar.refresh()
            return

        if self._message:
            self.status_bar.override_text = f" {self._message}"
            self.status_bar.refresh()
            return

        # Normal
        conn = self.connection_manager.get_display_string() if self._connected else "[dim]Not connected[/]"
        local = self.local_fs.get_current_path()
        remote = self.remote_fs.get_current_path() if self.remote_fs else ""
        self.status_bar.override_text = ""
        self.status_bar.update_status(
            local_path=local,
            remote_path=remote,
            connection_status=conn,
        )

    # ── Actions ───────────────────────────────────────────────────────

    def action_switch_pane(self) -> None:
        if not self._connected:
            self._message = "Not connected to remote"
            self._refresh_status_bar()
            return
        if self._focused_pane == "local":
            self._focused_pane = "remote"
            self.remote_table.focus()
        else:
            self._focused_pane = "local"
            self.local_table.focus()

    def action_quit(self) -> None:
        if self._connected:
            self.connection_manager.disconnect()
        self.app.exit()

    def action_connect(self) -> None:
        if self._connected:
            self.connection_manager.disconnect()
            self._connected = False
            self.remote_fs = None
            self.transfer_engine = None
            self.remote_table.display = False
            self.placeholder.display = True
            self.remote_table.clear()
            self._message = "Disconnected"
            self._refresh_status_bar()
            return
        # Open popup connect dialog
        self.app.push_screen(ConnectDialog(), self._on_connect_dialog_result)

    def action_copy_file(self) -> None:
        if not self._connected:
            self._message = "Not connected"
            self._refresh_status_bar()
            return
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        name = table.get_selected_name()
        path = table.get_selected_path()
        if not name or name == ".." or not path:
            self._message = "Nothing selected"
            self._refresh_status_bar()
            return
        self._enter_prompt("copy", path)

    def action_move_file(self) -> None:
        if not self._connected:
            self._message = "Not connected"
            self._refresh_status_bar()
            return
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        name = table.get_selected_name()
        path = table.get_selected_path()
        if not name or name == ".." or not path:
            self._message = "Nothing selected"
            self._refresh_status_bar()
            return
        self._enter_prompt("move", path)

    def action_new_dir(self) -> None:
        self._enter_prompt("new_dir")

    # ── Transfer ─────────────────────────────────────────────────────

    def action_upload(self) -> None:
        if not self._connected:
            self._message = "Not connected"
            self._refresh_status_bar()
            return
        if self._focused_pane != "local":
            return
        selected = self.local_table.get_selected_path()
        if not selected:
            return

        async def do():
            dest = f"{self.remote_fs.get_current_path()}/{Path(selected).name}"
            await self.transfer_engine.upload(local_path=selected, remote_path=dest)
            self._refresh_remote()
            self._message = f"Uploaded {Path(selected).name}"
            self._refresh_status_bar()

        self.run_worker(do())

    def action_download(self) -> None:
        if not self._connected:
            self._message = "Not connected"
            self._refresh_status_bar()
            return
        if self._focused_pane != "remote":
            return
        selected = self.remote_table.get_selected_path()
        if not selected:
            return

        async def do():
            dest = f"{self.local_fs.get_current_path()}/{Path(selected).name}"
            await self.transfer_engine.download(remote_path=selected, local_path=dest)
            self._refresh_local()
            self._message = f"Downloaded {Path(selected).name}"
            self._refresh_status_bar()

        self.run_worker(do())

    # ── Navigation ───────────────────────────────────────────────────

    def _navigate_into(self) -> None:
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        fs = self._get_fs()
        if not table.is_selected_directory():
            return
        path = table.get_selected_path()
        if not path:
            return
        try:
            fs.change_directory(path)
            self._refresh_pane()
            self._refresh_status_bar()
        except Exception as e:
            self._message = f"Error: {e}"
            self._refresh_status_bar()

    def _navigate_up(self) -> None:
        fs = self._get_fs()
        parent = str(Path(fs.get_current_path()).parent)
        try:
            fs.change_directory(parent)
            self._refresh_pane()
            self._refresh_status_bar()
        except Exception as e:
            self._message = f"Error: {e}"
            self._refresh_status_bar()

    def _get_fs(self):
        return self.local_fs if self._focused_pane == "local" else self.remote_fs

    def _refresh_pane(self):
        if self._focused_pane == "local":
            self._refresh_local()
        else:
            self._refresh_remote()

    def _refresh_local(self) -> None:
        try:
            self.local_table.load_local_directory(self.local_fs.get_current_path())
        except Exception as e:
            logger.error(f"Local refresh error: {e}")

    def _refresh_remote(self) -> None:
        if not self.remote_fs:
            return
        try:
            sftp = self.connection_manager.get_sftp()
            self.remote_table.load_remote_directory(sftp, self.remote_fs.get_current_path())
        except Exception as e:
            logger.error(f"Remote refresh error: {e}")

    # ── Delete / hidden ──────────────────────────────────────────────

    def _delete_selected(self) -> None:
        fs = self._get_fs()
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        name = table.get_selected_name()
        if not name or name == "..":
            return
        path = table.get_selected_path()
        if not path:
            return
        try:
            fs.delete(path)
            self._refresh_pane()
            self._message = f"Deleted {name}"
        except Exception as e:
            self._message = f"Delete error: {e}"
        self._refresh_status_bar()

    def _toggle_hidden(self) -> None:
        if self._focused_pane == "local":
            self.local_table.toggle_hidden_files()
            self._refresh_local()
        else:
            self.remote_table.toggle_hidden_files()
            self._refresh_remote()

    # ── Connect dialog callback ───────────────────────────────────────

    def _on_connect_dialog_result(self, result) -> None:
        if result is None:
            return  # user cancelled
        host, port_s, user, password, key_path = result

        for fn, val in [
            (validate_host, host),
            (validate_port, port_s),
            (validate_username, user),
        ]:
            ok, err = fn(val)
            if not ok:
                self._message = f"Error: {err}"
                self._refresh_status_bar()
                return
        if key_path:
            ok, err = validate_ssh_key_path(key_path)
            if not ok:
                self._message = f"Error: {err}"
                self._refresh_status_bar()
                return
        if not password and not key_path:
            self._message = "Error: password or SSH key required"
            self._refresh_status_bar()
            return

        self._message = "Connecting..."
        self._refresh_status_bar()

        try:
            self.connection_manager.connect(
                host=host, port=int(port_s), username=user,
                password=password or None, key_path=key_path or None,
            )
            sftp = self.connection_manager.get_sftp()
            self.remote_fs = RemoteFileSystem(sftp)
            self.transfer_engine = TransferEngine(sftp)
            self._connected = True
            self.placeholder.display = False
            self.remote_table.display = True
            self._refresh_remote()
            self._message = f"Connected to {host}"
        except (ConnectionError, Exception) as e:
            self._message = f"Connection error: {e}"
        self._refresh_status_bar()

    # ── Prompt execution ─────────────────────────────────────────────

    def _execute_copy(self) -> None:
        dest = self._prompt_buffer.strip()
        if not dest:
            self._message = "Empty destination"
            self._exit_prompt()
            return
        fs = self._get_fs()
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        src = self._prompt_source_path
        name = table.get_selected_name()
        if dest.endswith("/") or dest == ".":
            dest = f"{dest.rstrip('/')}/{name}"
        fs.copy(src, dest)
        self._refresh_pane()
        self._message = f"Copied {name} -> {dest}"
        self._exit_prompt()

    def _execute_move(self) -> None:
        dest = self._prompt_buffer.strip()
        if not dest:
            self._message = "Empty destination"
            self._exit_prompt()
            return
        fs = self._get_fs()
        table = self.local_table if self._focused_pane == "local" else self.remote_table
        src = self._prompt_source_path
        name = table.get_selected_name()
        if dest.endswith("/") or dest == ".":
            dest = f"{dest.rstrip('/')}/{name}"
        fs.rename(src, dest)
        self._refresh_pane()
        self._message = f"Moved {name} -> {dest}"
        self._exit_prompt()

    def _execute_new_dir(self) -> None:
        name = self._prompt_buffer.strip()
        if not name:
            self._message = "Empty name"
            self._exit_prompt()
            return
        fs = self._get_fs()
        dest = f"{fs.get_current_path()}/{name}"
        fs.create_directory(dest)
        self._refresh_pane()
        self._message = f"Created {name}"
        self._exit_prompt()

    # ── Key handling ─────────────────────────────────────────────────

    def on_key(self, event) -> None:
        key = event.key

        # Prompt mode (copy / move / new_dir — connect uses popup dialog)
        if self._prompt_mode:
            if key == "enter":
                if self._prompt_mode == "copy":
                    self._execute_copy()
                elif self._prompt_mode == "move":
                    self._execute_move()
                elif self._prompt_mode == "new_dir":
                    self._execute_new_dir()
                event.stop()
                return
            elif key == "escape":
                self._exit_prompt()
                event.stop()
                return
            elif key == "backspace":
                self._prompt_buffer = self._prompt_buffer[:-1]
                self._refresh_status_bar()
                event.stop()
                return
            else:
                # Use event.character for accurate character input (handles dot, etc.)
                ch = getattr(event, "character", None)
                if ch and ch.isprintable():
                    self._prompt_buffer += ch
                    self._refresh_status_bar()
                    event.stop()
                    return
            return

        # Normal mode
        if key == "enter":
            self._navigate_into()
            event.stop()
        elif key == "backspace":
            self._navigate_up()
            event.stop()
        elif key == "f5":
            self.action_upload()
            event.stop()
        elif key == "f6":
            self.action_download()
            event.stop()
        elif key == "delete":
            self._delete_selected()
            event.stop()
        elif key == "h":
            self._toggle_hidden()
            event.stop()
